declare
  l_img blob;
begin
  as_pdf.init;
  as_pdf.put_txt( 250, 800, '#PAGE_NR# / #PAGE_COUNT#', p_page_proc => 2 );
  l_img := hextoraw( '' );
  as_pdf.new_page;
  as_pdf.put_image( l_img, null, null, as_pdf.get( as_pdf.c_get_cp_page_width ), as_pdf.get( as_pdf.c_get_cp_page_height ), 'F', 'F' );
  as_pdf.put_image( l_img, null, null, as_pdf.get( as_pdf.c_get_cp_page_width ), as_pdf.get( as_pdf.c_get_cp_page_height ), 'F', 'F', 0.1, p_page_proc => 2 );
  as_pdf.new_page;
  as_pdf.query2table
    ( p_query => q'~select level x, 'test ' || level, sysdate + level t3, sysdate + 2 * level t4 from dual connect by level <= :1~'
    , p_x  => null, p_y  => null
    , p_options => '{ "binds":[125]
                    , "outline":{"title":"My report", "part":"my report, part #n#"}
                    , "columns":[,{"align":"C"},{"format":"dd-mon","align":"R" },{"fmt":"dd-mm-yyyy","width":80}]
                    , "widths":[25,60,60]
                    }'
    );
  l_img := hextoraw( '' );
  as_pdf.put_image( l_img, null, null, as_pdf.get( as_pdf.c_get_cp_page_width ), as_pdf.get( as_pdf.c_get_cp_page_height ), 'C', p_page_proc => 1 );
  as_pdf.save_pdf( 'APEX_HPROF_DIRECTORY', 'my.pdf' );
end;
/
